**Related Issues:** #35200

Example

```ts
// npm package A@v1
namespace A1 {
    // Structural hidden field across versions and packages.
    const tag = Symbol.for('TagName');
    export class A<T> {
        constructor(arg: T) { }
        [tag]: T;
    }
}
// npm package A@v2
namespace A2 {
    // Structural hidden field across versions and packages.
    const tag = Symbol.for('TagName');
    export class A<T> {
        constructor(arg: T) { }
        [tag]: T;
    }
    export declare function f(a: A<'a'>): void;
}
// npm package B
namespace B {
    A2.f(new A1.A('a')); // Should work.
}
```

```ts
